  2'b00: alucontrol = 3'b010; 
  2'b01: alucontrol = 3'b110; 
  2'b10: case (funct) 
  ADD: alucontrol = 3'b010; 
  SUB: alucontrol = 3'b110; 
  AND: alucontrol = 3'b000; 
  OR: alucontrol = 3'b001; 
  SLT: alucontrol = 3'b111; 
  endcase 
  endcase 
