  assign LowLogicImm[i] = (LowMaskSel_Bot <= i[5:0]); 
  assign HighLogicImm[i] = (HighMaskSel_Bot >= i[5:0]); 
  end 
  end 
  endgenerate 
  assign LogicImm = LowLogicImm & HighLogicImm; 
