reg xPosLED[1:0]; 
  reg yPosLED[1:0]; 
  always@(posedge clk) 
  begin 
  if (xpos < 384) begin 
  xPosLED[0] <= 1'b1; 
  end 
  else begin 
  xPosLED[0] <= 1'b0; 
  end 
