  integer data_src; 
  integer i; 
  integer j; 
  initial 
  begin 
  rxd_buf = 0; 
  clk_buf = 1; 
  data_src = $fopen("test_serializer/data/serial_vector.txt", "rb"); 
  #100; 
  for(i = 0; i < 16*(8+4); i = i + 1) 
  begin 
  #1; 
