  #2; 
  clk_buf = 0; 
  #2; 
  clk_buf = 1; 
  #2; 
  clk_buf = 0; 
  #2; 
  clk_buf = 1; 
  #2; 
  clk_buf = 0; 
  #2; 
  clk_buf = 1; 
  $fclose(data_src); 
  end 
