module origen_053032 #(
    parameter MAX_AMOUNT = 22,
    parameter F_TESTID = 1
) (
    input wire i_clk,
    input wire i_start_signal,
    output wire o_busy
);

    reg [15:0] counter;

    assign o_busy = (counter != 0);

    always @(posedge i_clk) begin
        if (counter == 0 && i_start_signal)
            counter <= MAX_AMOUNT - 1;
        else if (counter > 0)
            counter <= counter - 1;
    end

`ifdef FORMAL
    always @(*) begin
        assert(counter < MAX_AMOUNT);
    end

    generate
        if (F_TESTID == 1) begin : F_TESTID_ONE
            always @(*) begin
                assume(i_start_signal == 0);
                assert(counter == 0);
            end
        end
        else if (F_TESTID == 2) begin : F_TESTID_TWO
            always @(*) begin
                if (i_start_signal == 0)
                    assert(counter == 0);
            end
        end
        else if (F_TESTID == 3) begin : F_TESTID_THREE
            always @(posedge i_clk) begin
                if ($past(i_start_signal) && $past(counter == 0))
                    assert(counter == MAX_AMOUNT - 1);
            end
        end
        else if (F_TESTID == 4) begin : F_TESTID_FOUR
            always @(posedge i_clk) begin
                if ($past(i_start_signal) && $past(counter == 0) && $past_valid)
                    assert(counter == MAX_AMOUNT - 1);
            end
        end
    endgenerate
`endif

endmodule

