always @(posedge clk or posedge reset) begin
    if (reset) begin
        proc_dout_reg <= 32'b0;
        XRF_ADDR_reg  <= 5'b0;
        XRF_DATAWR_reg<= 32'b0;
        XRF_WE_reg    <= 1'b0;
        ALU_mon_reg   <= 1'b0;
        stall_reg     <= 1'b0;
        DONE_reg      <= 1'b0;
    end else begin
        if (proc_we) begin
            proc_dout_reg <= proc_din;
