            proc_dout_reg <= proc_dout_reg;
        end

        if (I_start) begin
            XRF_ADDR_reg <= I_vs1;
            XRF_DATAWR_reg <= I_RS1;
            XRF_WE_reg <= I_reg_we;
        end else begin
            XRF_ADDR_reg <= 5'b0;
            XRF_DATAWR_reg <= 32'b0;
