            if (ENABLE == 1'b1 && RS == 1'b1) begin
                if (nWR == 1'b1) begin
                    shift_reg <= 9'b111111111;
                end else begin
                    shift_reg <= {DI, 1'b1};
                end
                done <= 1'b0;
                counter <= 4'b0000;
            end
        end else begin
            counter <= counter + 1;
            if (counter[0] == 1'b0) begin
                shift_reg[0] <= SD_MISO;
            end else begin
                shift_reg <= {shift_reg[7:0], 1'b1};
            end
        end
    end
end

endmodule

