            data_in_buffer[17] ^ data_in_buffer[16] ^ data_in_buffer[15] ^ 
            data_in_buffer[14] ^ data_in_buffer[13] ^ data_in_buffer[12] ^ 
            data_in_buffer[11] ^ data_in_buffer[10] ^ data_in_buffer[9] ^ 
