module mux_3bit_5to1 (S, U, V, W, X, Y, M);
    input [2:0] S, U, V, W, X, Y;
    output reg [2:0] M;

    always @(*)
    begin
        case (S)
            3'b000: M = U;
            3'b001: M = V;
            3'b010: M = W;
            3'b011: M = X;
            3'b100: M = Y;
            default: M = Y;
        endcase
    end
