module rtlpp_08552 (
  input               clk,          
  input               reset,        
  input               data_in,      
  output reg [15:0]   data_out,     
  output reg          data_en,
  input      [15:0]   dec_rate
);

  reg [36:0]  data_int = 37'h0;
  reg [36:0]  acc1 = 37'h0;
  reg [36:0]  acc2 = 37'h0;
  reg [36:0]  acc3 = 37'h0;
  reg [36:0]  acc3_d = 37'h0;
  reg [36:0]  diff1 = 37'h0;
  reg [36:0]  diff2 = 37'h0;
  reg [36:0]  diff3 = 37'h0;
  reg [36:0]  diff1_d = 37'h0;
  reg [36:0]  diff2_d = 37'h0;
  reg [15:0]  word_count = 16'h0;
  reg         word_clk = 1'b0;
  reg         enable = 1'b0;

  always @(data_in) begin
    if (data_in==0)
      data_int <= 37'd0;
    else 
      data_int <= 37'd1;
  end

  always @(negedge clk) begin
    if (reset == 1'b0) begin
      acc1 <= 37'd0;
      acc2 <= 37'd0;
      acc3 <= 37'd0;
    end else begin
      acc1 <= acc1 + data_int;
      acc2 <= acc2 + acc1;
      acc3 <= acc3 + acc2;
    end
  end

  always @(posedge clk) begin
    if (reset == 1'b1) begin
      word_count <= 16'd0;
    end else begin
      if (word_count == (dec_rate - 1))
        word_count <= 16'd0;
      else
        word_count <= word_count + 16'b1;
    end
  end

  always @(posedge clk) begin
    if (reset == 1'b0) begin
      word_clk <= 1'b0;
    end else begin
      if (word_count == (dec_rate/2 - 1))
        word_clk <= 1'b1;
      else if (word_count == (dec_rate - 1))
        word_clk <= 1'b0;
    end
  end

  always @(posedge word_clk) begin
    if (reset == 1'b1) begin
      acc3_d <= 37'd0;
      diff1_d <= 37'd0;
      diff2_d <= 37'd0;
      diff1   <= 37'd0;
      diff2   <= 37'd0;
      diff3   <= 37'd0;
    end else begin
      diff1   <= acc3 - acc3_d;
      diff2   <= diff1 - diff1_d;
      diff3   <= diff2 - diff2_d;
      acc3_d  <= acc3;
      diff1_d <= diff1;
      diff2_d <= diff2;
    end
  end

  always @(posedge word_clk) begin
    case (dec_rate)
      16'd32: begin
        data_out <= (diff3[15:0] == 16'h8000) ? 16'hFFFF : {diff3[14:0], 1'b0};
      end
      16'd64: begin
        data_out <= (diff3[18:2] == 17'h10000) ? 16'hFFFF : diff3[17:2];
      end
      16'd128: begin
        data_out <= (diff3[21:5] == 17'h10000) ? 16'hFFFF : diff3[20:5];
      end
      16'd256: begin
        data_out <= (diff3[24:8] == 17'h10000) ? 16'hFFFF : diff3[23:8];
      end
      16'd512: begin
        data_out <= (diff3[27:11] == 17'h10000) ? 16'hFFFF : diff3[26:11];
      end
      16'd1024: begin
        data_out <= (diff3[30:14] == 17'h10000) ? 16'hFFFF : diff3[29:14];
      end
      16'd2048: begin
        data_out <= (diff3[33:17] == 17'h10000) ? 16'hFFFF : diff3[32:17];
      end
      16'd4096: begin
        data_out <= (diff3[36:20] == 17'h10000) ? 16'hFFFF : diff3[35:20];
      end
      default: begin
        data_out <= (diff3[24:8] == 17'h10000) ? 16'hFFFF : diff3[23:8];
      end
    endcase
  end

  always @(posedge clk) begin
    if (reset == 1'b1) begin
      data_en <= 1'b0;
      enable <= 1'b1;
    end else begin
      if ((word_count == (dec_rate/2 - 1)) && (enable == 1'b1)) begin
        data_en <= 1'b1;
        enable <= 1'b0;
      end else if ((word_count == (dec_rate - 1)) && (enable == 1'b0)) begin
        data_en <= 1'b0;
        enable <= 1'b1;
      end else
        data_en <= 1'b0;
    end
  end

endmodule

