module autovcoder_005436 (
    a,
    b,
    bin,
    diff,
    bout
);

  input [15:0] a;
  input [15:0] b;
  input bin;

  output [15:0] diff;
  output bout;

  wire w0, w1, w2, w3, w4, w5, w6, w7, w8, w9, w10, w11, w12, w13, w14, w15;

  // Design implementation
  // Using the previous module of a single bit full subtractor
  // this 16-bit subtractor can be created by instantiating
  // the FS module and adding wires to connect each block together to 
  // form a 16-bit subtractor.
  FS F0 (
      a[0],
      b[0],
      bin,
      diff[0],
      w0
  );
  FS F1 (
      a[1],
      b[1],
      w0,
      diff[1],
      w1
  );
  FS F2 (
      a[2],
      b[2],
      w1,
      diff[2],
      w2
  );
  FS F3 (
      a[3],
      b[3],
      w2,
      diff[3],
      w3
  );
  FS F4 (
      a[4],
      b[4],
      w3,
      diff[4],
      w4
  );
  FS F5 (
      a[5],
      b[5],
      w4,
      diff[5],
      w5
  );
  FS F6 (
      a[6],
      b[6],
      w5,
      diff[6],
      w6
  );
  FS F7 (
      a[7],
      b[7],
      w6,
      diff[7],
      w7
  );
  FS F8 (
      a[8],
      b[8],
      w7,
      diff[8],
      w8
  );
  FS F9 (
      a[9],
      b[9],
      w8,
      diff[9],
      w9
  );
  FS F10 (
      a[10],
      b[10],
      w9,
      diff[10],
      w10
  );
  FS F11 (
      a[11],
      b[11],
      w10,
      diff[11],
      w11
  );
  FS F12 (
      a[12],
      b[12],
