  output reg s_axi_arready,
  output reg [15:0] s_axi_rid,
  output reg [31:0] s_axi_rdata,
  output reg [1:0] s_axi_rresp,
  output reg s_axi_rlast,
  output reg s_axi_rvalid,
  input s_axi_rready,
  output reg [39:0] m_axi_awaddr,
  output reg [2:0] m_axi_awprot,
  output reg m_axi_awvalid,
  input m_axi_awready,
  output reg [31:0] m_axi_wdata,
  output reg [3:0] m_axi_wstrb,
  output reg m_axi_wvalid,
  input m_axi_wready,
  input [1:0] m_axi_bresp,
  input m_axi_bvalid,
  output reg m_axi_bready,
  output reg [39:0] m_axi_araddr,
  output reg [2:0] m_axi_arprot,
  output reg m_axi_arvalid,
  input m_axi_arready,
  input [31:0] m_axi_rdata,
  input [1:0] m_axi_rresp,
  input m_axi_rvalid,
  output reg m_axi_rready
);
  // Internal signals
  reg [31:0] awaddr_reg, wdata_reg, araddr_reg;

  // Write address channel handshake
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      s_axi_awready <= 1'b0;
      awaddr_reg <= 32'b0;
    end else if (s_axi_awvalid && !s_axi_awready) begin
      s_axi_awready <= 1'b1;
      awaddr_reg <= s_axi_awaddr[31:0]; // Example address latching
    end else begin
      s_axi_awready <= 1'b0;
    end
  end

  // Write data channel handshake
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      s_axi_wready <= 1'b0;
      wdata_reg <= 32'b0;
    end else if (s_axi_wvalid && !s_axi_wready) begin
      s_axi_wready <= 1'b1;
      wdata_reg <= s_axi_wdata; // Example data latching
    end else begin
      s_axi_wready <= 1'b0;
    end
  end

  // Write response handshake
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      s_axi_bvalid <= 1'b0;
      s_axi_bresp <= 2'b00;
      s_axi_bid <= 16'b0;
    end else if (s_axi_wready && s_axi_wvalid && s_axi_bready) begin
      s_axi_bvalid <= 1'b1;
      s_axi_bresp <= 2'b00; // OKAY response
      s_axi_bid <= s_axi_awid;
    end else begin
      s_axi_bvalid <= 1'b0;
    end
  end

  // Read address channel handshake
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      s_axi_arready <= 1'b0;
      araddr_reg <= 32'b0;
    end else if (s_axi_arvalid && !s_axi_arready) begin
      s_axi_arready <= 1'b1;
      araddr_reg <= s_axi_araddr[31:0]; // Example address latching
    end else begin
      s_axi_arready <= 1'b0;
    end
  end

  // Read data channel handshake
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      s_axi_rvalid <= 1'b0;
      s_axi_rresp <= 2'b00;
      s_axi_rid <= 16'b0;
      s_axi_rdata <= 32'b0;
      s_axi_rlast <= 1'b0;
    end else if (s_axi_arready && s_axi_arvalid && s_axi_rready) begin
      s_axi_rvalid <= 1'b1;
      s_axi_rresp <= 2'b00; // OKAY response
      s_axi_rid <= s_axi_arid;
      s_axi_rdata <= 32'b0; // Example data
      s_axi_rlast <= 1'b1;  // Single beat transfer
    end else begin
      s_axi_rvalid <= 1'b0;
    end
  end

  // Connect the output signals to internal registers or fixed values
  always @(*) begin
    m_axi_awaddr = awaddr_reg;
    m_axi_awprot = 3'b000;
    m_axi_awvalid = s_axi_awready;

    m_axi_wdata = wdata_reg;
    m_axi_wstrb = s_axi_wstrb;
    m_axi_wvalid = s_axi_wready;

    m_axi_bready = s_axi_bready;

    m_axi_araddr = araddr_reg;
    m_axi_arprot = 3'b000;
    m_axi_arvalid = s_axi_arready;

    m_axi_rready = s_axi_rready;
  end
endmodule

