module autovcoder_079895 (
    CLOCK_50,  //	On Board 50 MHz
    // Your inputs and outputs here
    KEY,
    SW,
    HEX0,
    HEX3,
    HEX2,
    HEX4,
    LEDR,
    PS2_CLK,
    PS2_DAT,
    // The ports below are for the VGA output.  Do not change.
    VGA_CLK,  //	VGA Clock
    VGA_HS,  //	VGA H_SYNC
    VGA_VS,  //	VGA V_SYNC
    VGA_BLANK_N,  //	VGA BLANK
    VGA_SYNC_N,  //	VGA SYNC
    VGA_R,  //	VGA Red[9:0]
    VGA_G,  //	VGA Green[9:0]
    VGA_B  //	VGA Blue[9:0]
);

  inout PS2_CLK;
  inout PS2_DAT;

  input CLOCK_50;  //	50 MHz
  input [9:0] SW;
  input [3:0] KEY;
  output [6:0] HEX0;
  output [6:0] HEX4;

  output [6:0] HEX3;
  output [6:0] HEX2;

  output [9:0] LEDR;


  // Declare your inputs and outputs here
  // Do not change the following outputs
  output VGA_CLK;  //	VGA Clock
  output VGA_HS;  //	VGA H_SYNC
  output VGA_VS;  //	VGA V_SYNC
  output VGA_BLANK_N;  //	VGA BLANK
  output VGA_SYNC_N;  //	VGA SYNC
  output [9:0] VGA_R;  //	VGA Red[9:0]
  output [9:0] VGA_G;  //	VGA Green[9:0]
  output [9:0] VGA_B;  //	VGA Blue[9:0]

  wire resetn;  //VGA reset low
  assign resetn = SW[0];

  // Create the colour, x, y and writeEn wires that are inputs to the controller.
  wire [2:0] colour;
  wire [10:0] x;
  wire [10:0] y;
  wire writeEn;

  // Create an Instance of a VGA controller - there can be only one!
  // Define the number of colours as well as the initial background
  // image file (.MIF) for the controller.
  vga_adapter VGA (
      .resetn(~resetn),
      .clock(CLOCK_50),
      .colour(colour),
      .x(x),
      .y(y),
      .plot(writeEn),
      /* Signals for the DAC to drive the monitor. */
      .VGA_R(VGA_R),
      .VGA_G(VGA_G),
      .VGA_B(VGA_B),
      .VGA_HS(VGA_HS),
      .VGA_VS(VGA_VS),
      .VGA_BLANK(VGA_BLANK_N),
      .VGA_SYNC(VGA_SYNC_N),
      .VGA_CLK(VGA_CLK)
  );
  defparam VGA.RESOLUTION = "320x240"; defparam VGA.MONOCHROME = "FALSE";
      defparam VGA.BITS_PER_COLOUR_CHANNEL = 1; defparam VGA.BACKGROUND_IMAGE = "black.mif";

  // Put your code here. Your code should produce signals x,y,colour and writeEn/plot
  // for the VGA controller, in addition to any other functionality your design may require.
  wire clear_signal, enable, enable_erase, enable_update, enable_fcounter, next_box, y_count_done, next_boxx, game_end;
  wire [3:0] p1_curr_score, p2_curr_score;
  wire [9:0] control;
  wire [3:0] digit_1, digit_2;

  wire [3:0] time_1, time_2;



  paddle_sim po (
      .clock(CLOCK_50),
      .reset_n(resetn),
      .go(~KEY[0]),
      .p1_up(control[1]),
      .p1_down(control[3]),
      .p1_left(control[2]),
      .p1_right(control[4]),
      .p2_up(control[7]),
      .p2_down(control[8]),
      .p2_left(control[5]),
      .p2_right(control[6]),
      .x(x),
      .y(y),
      .colour_out(colour),
      .writeEn(writeEn),
      .p1_curr_score(p1_curr_score),
      .p2_curr_score(p2_curr_score),
      .timer_digit_1(time_1),
      .timer_digit_2(time_2),
      // .p1_score(~KEY[2]), .p2_score(~KEY[1]),
      .p1_scoret(LEDR[1]),
      .p2_scoret(LEDR[0]),
      .game_end_out(game_end)
  );

  hex_decoder h0 (
      p2_curr_score / 2,
      HEX0
  );

  hex_decoder h1 (
      p1_curr_score / 2,
      HEX4
  );


  hex_decoder h2 (
      digit_1,
      HEX3
  );

  hex_decoder h3 (
      digit_2,
      HEX2
  );

  assign LEDR[3] = game_end;

  comparator(
      .player_1_score(p1_curr_score),
      .player_2_score(p2_curr_score),
      .time_digit_1(time_1),
      .time_digit_2(time_2),
      .digit_1(digit_1),
      .digit_2(digit_2),
      .enable(game_end),
      .clock(CLOCK_50)
  );



  keyboard_tracker #(
      .PULSE_OR_HOLD(0)
  ) tester (
      .clock(CLOCK_50),
      .reset(~resetn),
      .PS2_CLK(PS2_CLK),
      .PS2_DAT(PS2_DAT),
      .w(control[1]),
      .a(control[2]),
      .s(control[3]),
      .d(control[4]),
      .left(control[5]),
      .right(control[6]),
      .up(control[7]),
      .down(control[8]),
      .space(control[9]),
      .enter(control[0])
  );

endmodule

