module autovcoder_002766 (
    a,
    b,
    sum
);
  input [31:0] a, b;
  output [32:0] sum;
  wire [31:0] p, g;
  wire [6:0] appc, cout, c;
  wire bp1, bp2, bp3, bp4, bp5, bp6;

  assign p = a ^ b;
  assign g = a & b;
  appc app0 (
      p[3:0],
      g[3:0],
      appc[0]
  );
  appc app1 (
      p[7:4],
      g[7:4],
      appc[1]
  );
  appc app2 (
      p[11:8],
      g[11:8],
      appc[2]
  );
  appc app3 (
      p[15:12],
      g[15:12],
      appc[3]
  );
  appc app4 (
      p[19:16],
      g[19:16],
      appc[4]
  );
  appc app5 (
      p[23:20],
      g[23:20],
      appc[5]
  );
  appc app6 (
      p[27:24],
      g[27:24],
      appc[6]
  );
  assign bp1  = p[7] & p[6] & p[5] & p[4];
  assign bp2  = p[11] & p[10] & p[9] & p[8];
  assign bp3  = p[15] & p[14] & p[13] & p[12];
  assign bp4  = p[19] & p[18] & p[17] & p[16];
  assign bp5  = p[23] & p[22] & p[21] & p[20];
  assign bp6  = p[27] & p[26] & p[25] & p[24];

  assign c[0] = appc[0];
  csu cin2 (
      bp1,
      appc[1],
      g[3],
      1'b0,
      1'b0,
      c[1]
  );
  csu cin3 (
      bp2,
      appc[2],
      g[7],
      1'b0,
      1'b0,
      c[2]
  );
  csu cin4 (
      bp3,
      appc[3],
      g[11],
      1'b0,
      1'b0,
      c[3]
  );
  csu cin5 (
      bp4,
      appc[4],
      g[15],
      1'b0,
      1'b0,
      c[4]
  );
  csu cin6 (
      bp5,
      appc[5],
      g[19],
      1'b0,
      1'b0,
      c[5]
  );
  csu cin7 (
      bp6,
      appc[6],
      g[23],
      1'b0,
      1'b0,
      c[6]
  );

  carry_look_ahead_4bit cla1 (
      p[3:0],
      g[3:0],
      1'b0,
      sum[3:0],
      cout[0]
  );
  carry_look_ahead_4bit cla2 (
      p[7:4],
      g[7:4],
      c[0],
      sum[7:4],
      cout[1]
  );
  carry_look_ahead_4bit cla3 (
      p[11:8],
      g[11:8],
      c[1],
      sum[11:8],
      cout[2]
  );
  carry_look_ahead_4bit cla4 (
      p[15:12],
      g[15:12],
      c[2],
      sum[15:12],
      cout[3]
  );
  carry_look_ahead_4bit cla5 (
      p[19:16],
      g[19:16],
      c[3],
      sum[19:16],
      cout[4]
  );
  carry_look_ahead_4bit cla6 (
      p[23:20],
      g[23:20],
      c[4],
      sum[23:20],
      cout[5]
  );
  carry_look_ahead_4bit cla7 (
      p[27:24],
      g[27:24],
      c[5],
      sum[27:24],
      cout[6]
  );
  carry_look_ahead_4bit cla8 (
      p[31:28],
      g[31:28],
      c[6],
      sum[31:28],
      sum[32]
  );
endmodule

files.conformal_rtl_autovcoder_002766.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

