module autovcoder_103203 (
    clk,
    reset,
    startReg,
    signD,
    wasTMove,
    alarmaVisual,
    alarmaSonora
);
  input clk;  //Reloj del sistema
  input reset;  //Reset del sistema
  input startReg;  //Inicio del registro
  input signD;  //Seal de movimiento externa
  output reg wasTMove;  //Registro del movimiento
  output reg alarmaVisual;  //Alarmas del sistema
  output reg alarmaSonora;
  reg rst, startR, sigD;
  //Asignaciones para evitar el error HDLCompiler:1660
  assign reset = rst;
  assign startReg = startR;
  assign signD = sigD;
  initial begin  //Parametros de inicio
    rst = 0;
    startR = 0;
    sigD = 0;
    wasTMove = 0;
  end
  always @(posedge clk) begin  //Bloque del reset
    if (rst == 1) begin
      startR = 0;
      sigD = 0;
      wasTMove = 0;
    end
  end
  always @(posedge clk or posedge startR or negedge rst) begin  //Bloque de ejecucin
    if (sigD == 1) wasTMove = 1;
    if (wasTMove == 1) begin
      alarmaVisual = 1;
      alarmaSonora = 1;
    end else begin
      alarmaVisual = 0;
      alarmaSonora = 0;
    end
  end
endmodule

files.autovcoder_026461.v:
module autovcoder_026461 (
    input      clk,
    n_reset,
    button_in,  // inputs
    output reg DB_out  // output
);
  //// ---------------- internal constants --------------
  parameter N = 11;  // (2^ (21-1) )/ 38 MHz = 32 ms debounce time
  ////---------------- internal variables ---------------
  reg [N-1 : 0] q_reg;  // timing regs
  reg [N-1 : 0] q_next;
  reg DFF1, DFF2;  // input flip-flops
  wire q_add;  // control flags
  wire q_reset;
  //// ------------------------------------------------------

  ////contenious assignment for counter control
  assign q_reset = (DFF1 ^ DFF2);  // xor input flip flops to look for level chage to reset counter
  assign q_add   = ~(q_reg[N-1]);  // add to counter when q_reg msb is equal to 0

  //// combo counter to manage q_next	
  always @(q_reset, q_add, q_reg) begin
    case ({
      q_reset, q_add
    })
      2'b00:   q_next <= q_reg;
      2'b01:   q_next <= q_reg + 1;
      default: q_next <= {N{1'b0}};
    endcase
  end

  //// Flip flop inputs and q_reg update
  always @(posedge clk) begin
    if (n_reset == 1'b0) begin
      DFF1  <= 1'b0;
      DFF2  <= 1'b0;
      q_reg <= {N{1'b0}};
    end else begin
      DFF1  <= button_in;
      DFF2  <= DFF1;
      q_reg <= q_next;
    end
  end

  //// counter control
  always @(posedge clk) begin
    if (q_reg[N-1] == 1'b1) DB_out <= DFF2;
    else DB_out <= DB_out;
  end

endmodule

files.autovcoder_102886.v:
module autovcoder_102886 (
    input clk,
    input rst,

    // SD Card interface
    output reg sd_clk,
    output sd_mosi,
    input sd_miso,

    // Controls
    input [7:0] clk_div,
    input [7:0] send_dat,
    output [7:0] rcv_dat,
    input go,
    output ready
);

  reg  [7:0] clk_ctr;
  reg  [3:0] bit_ctr;

  wire       bit_ready = (clk_ctr == 8'd0);
  wire       bit_busy = (clk_ctr != 8'd0);
  wire       bit_done = (clk_ctr == clk_div);

  wire       send_clk_hi = (clk_ctr == (clk_div >> 1));
  wire       latch_dat = (clk_ctr == (clk_div - 8'd2));
  wire       send_clk_lo = (clk_ctr == (clk_div - 8'd1));

  wire       send_bit = (bit_ready && (bit_ctr != 0));
  assign ready = (bit_ctr == 0);

  always @(posedge clk)
    if (rst) clk_ctr <= 0;
    else if (bit_done) clk_ctr <= 0;
    else if (bit_busy) clk_ctr <= clk_ctr + 1;
    else if (send_bit) clk_ctr <= 1;

  always @(posedge clk)
    if (rst) sd_clk <= 0;
    else if (send_clk_hi) sd_clk <= 1;
    else if (send_clk_lo) sd_clk <= 0;

  always @(posedge clk)
    if (rst) bit_ctr <= 0;
    else if (bit_done)
      if (bit_ctr == 4'd8) bit_ctr <= 0;
      else bit_ctr <= bit_ctr + 1;
    else if (bit_ready & go) bit_ctr <= 1;

  reg [7:0] shift_reg;
  always @(posedge clk)
    if (go) shift_reg <= send_dat;
    else if (latch_dat) shift_reg <= {shift_reg[6:0], sd_miso};

  assign sd_mosi = shift_reg[7];
  assign rcv_dat = shift_reg;

endmodule

files.autovcoder_135775.v:
module autovcoder_135775(
    input clk,
    input rst,
    input [511:0] data_in,
    input start,
    output reg [127:0] hash_out,
    output reg done
);

    reg [127:0] a, b, c, d;
    reg [3:0] state; // state machine for processing
    reg [4:0] round;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= 0;
            a <= 32'h67452301;
            b <= 32'hEFCDAB89;
            c <= 32'h98BADCFE;
            d <= 32'h10325476;
            hash_out <= 0;
            done <= 0;
            round <= 0;
        end else if (start) begin
            case (state)
                0: begin // Initialization
                    state <= 1;
                end
                1: begin // Process input data
                    // Simplified processing, just an example
                    a <= a + data_in[127:0] + (b & c | ~b & d);
                    b <= b + data_in[255:128] + (a & d | c & ~a);
                    c <= c + data_in[383:256] + (b & a | d & ~b);
                    d <= d + data_in[511:384] + (c & b | a & ~c);
                    round <= round + 1;
                    if (round == 4) begin
                        state <= 2; // Proceed to final state
                    end
                end
                2: begin // Final output
                    hash_out <= {a, b, c, d};
                    done <= 1;
                    state <= 0; // Reset state
                end
            endcase
        end
    end
endmodule

