module origen_015115 (
    input wire clk,
    input wire valid_box,
    input wire [63:0] bbox_in,
    output wire [63:0] bbox_out_0,
    output wire [63:0] bbox_out_1,
    output wire [63:0] bbox_out_2,
    output wire [63:0] bbox_out_3,
    output wire [63:0] bbox_out_4,
    output wire [63:0] bbox_out_5,
    output wire [63:0] bbox_out_6,
    output wire [63:0] bbox_out_7,
    output wire [63:0] bbox_out_8,
    output wire [63:0] bbox_out_9
);

    reg [63:0] bbox_reg [0:9];
    reg [3:0] current_bbox;
    reg [2:0] pass_cnt;

    integer i;
    initial begin
        for (i = 0; i < 10; i = i + 1) begin
            bbox_reg[i] = 64'b1;
        end
        current_bbox = 4'd0;
        pass_cnt = 3'd0;
