    output reg [15:0] To_Hex
);

    reg Hw_in, Hw_in_in;
    reg [15:0] FACE, FACE_in;
    reg [7:0] counter, counter_in;
    reg [7:0] avg_sum, avg_sum_in;

    always @(posedge Clk or posedge RST) begin
        if (RST) begin
            counter <= 8'd41;
            Hw_in <= 1'b0;
            FACE <= 16'h0000;
            avg_sum <= 8'd0;
