            8'h31: dataout <= "n";
            8'h44: dataout <= "o";
            8'h4D: dataout <= "p";
            8'h15: dataout <= "q";
            8'h2D: dataout <= "r";
            8'h1B: dataout <= "s";
            8'h2C: dataout <= "t";
            8'h3C: dataout <= "u";
            8'h2A: dataout <= "v";
            8'h1D: dataout <= "w";
            8'h22: dataout <= "x";
            8'h35: dataout <= "y";
            8'h1A: dataout <= "z";
            8'h45: dataout <= "0";
            8'h16: dataout <= "1";
            8'h1E: dataout <= "2";
            8'h26: dataout <= "3";
            8'h25: dataout <= "4";
            8'h2E: dataout <= "5";
            8'h36: dataout <= "6";
            8'h3D: dataout <= "7";
            8'h3E: dataout <= "8";
            8'h46: dataout <= "9";
            8'hF0: dataout <= 8'h00;
            default: dataout <= 8'h00;
        endcase
    end
end

endmodule

